import { useParams, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../api";
import "./styles/Books.css";

/* 🔹 EXTRA DETAILS (STATIC FOR NOW – BACKEND READY) */
const bookExtraDetails = {
  "Harry Potter": {
    about:
     "Harry Potter lives with his abusive uncle and aunt, Vernon and Petunia Dursley, and their bullying son, Dudley, in the fictional English town of Little Whinging. On Harry's eleventh birthday, he learns that he is a wizard when a man named Rubeus Hagrid invites him to attend Hogwarts, a school of magic.",
    authorInfo:
      "J.K. Rowling is a British author best known for creating the Harry Potter series, one of the most successful literary franchises in history."
  },

  "The Hobbit": {
    about:
      "The Hobbit follows Bilbo Baggins on an unexpected adventure involving dragons, treasure, and bravery.",
    authorInfo:
      "J.R.R. Tolkien was an English writer and scholar, considered the father of modern fantasy.",
    reviews: [
      "⭐️⭐️⭐️⭐️⭐️ Timeless fantasy.",
      "⭐️⭐️⭐️⭐️ A beautiful journey."
    ]
  }
};

function BooksDetails() {
  const { title, author, cover } = useParams();
  const navigate = useNavigate();

  const decodedTitle = decodeURIComponent(title);
  const decodedAuthor = decodeURIComponent(author);
  const decodedCover = decodeURIComponent(cover);

  const [isBorrowed, setIsBorrowed] = useState(false);

  const extra = bookExtraDetails[decodedTitle];

  useEffect(() => {
    api
      .get(`/books/${encodeURIComponent(decodedTitle)}/status`)
      .then(res => setIsBorrowed(res.data.isBorrowed))
      .catch(() => setIsBorrowed(false));
  }, [decodedTitle]);

  const borrowBook = async () => {
    try {
      await api.post(`/books/${encodeURIComponent(decodedTitle)}/borrow`);
      setIsBorrowed(true);
    } catch {}
  };

  const returnBook = async () => {
    try {
      await api.post(`/books/${encodeURIComponent(decodedTitle)}/return`);
      setIsBorrowed(false);
    } catch {}
  };

  return (
    <div className="books-page">
      {/* 🔹 EXISTING CARD (UNCHANGED) */}
      <div className="detail-card">
        <img src={decodedCover} alt={decodedTitle} />

        <h2>{decodedTitle}</h2>
        <p>{decodedAuthor}</p>

        <p className="status">
          Status:{" "}
          <span className={isBorrowed ? "not-avail" : "avail"}>
            {isBorrowed ? "Not Available" : "Available"}
          </span>
        </p>

        {!isBorrowed ? (
          <button className="main-cta" onClick={borrowBook}>
            Borrow Book
          </button>
        ) : (
          <button className="return-btn" onClick={returnBook}>
            Return Book
          </button>
        )}

        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back to Library
        </button>
      </div>

      {/* 🔹 NEW: EXTRA DETAILS SECTION */}
      {extra && (
        <div className="book-extra-section">
          <h3>About the Book</h3>
          <p>{extra.about}</p>

          <h3>About the Author</h3>
          <p>{extra.authorInfo}</p>

          <h3>Reviews</h3>
          <ul>
            {extra.reviews.map((review, index) => (
              <li key={index}>{review}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default BooksDetails;
